import React, { useState, useEffect } from "react";
import ReactDOM from "react-dom/client";
import "./index.css";
import "./assets/fonts/stylesheet.css";
import App from "./App";
import reportWebVitals from "./reportWebVitals";
import { BrowserRouter, useParams, useSearchParams } from "react-router";

const root = ReactDOM.createRoot(document.getElementById("root"));

const AppData = () => {
  const [lastRefresh, setLastRefresh] = useState(
    new Date().toLocaleTimeString(),
  );
  const [searchParams] = useSearchParams();
  const arrItems = ["dilsere", "online"];
  const data = searchParams.get("data");

  useEffect(() => {
    const checkAndRefresh = () => {
      const now = new Date();
      const dayOfWeek = now.getDay(); // 0 (Sun) to 6 (Sat)
      const currentTimeInMinutes = now.getHours() * 60 + now.getMinutes();

      const isWeekday = dayOfWeek >= 1 && dayOfWeek <= 5;
      const startTime = 9 * 60 + 15; // 09:15 AM
      const endTime = 15 * 60 + 30; // 03:15 PM

      if (
        isWeekday &&
        currentTimeInMinutes >= startTime &&
        currentTimeInMinutes <= endTime
      ) {
        console.log("Within window: Refreshing data...");
        // Option: window.location.reload(); // For full page refresh
        setLastRefresh(new Date().toLocaleTimeString()); // For data-only refresh
        const element = document.getElementById("refreshElement");
        if (element && isMarketOpen) {
          element.click();
        }
      } else {
        console.log("Outside window (Weekend or After Hours): No refresh.");
      }
    };

    // Set interval for 3 minutes (180,000ms)
    const intervalId = setInterval(checkAndRefresh, 180000);

    // Initial check on load
    checkAndRefresh();

    return () => clearInterval(intervalId);
  }, []);
  return arrItems.includes(data) ? (
    <>
      <App lastRefresh={lastRefresh} isMarketOpen={isMarketOpen} />
    </>
  ) : (
    <p className="whiteColour">went something wrong</p>
  );
};

root.render(
  <BrowserRouter>
    <AppData />
  </BrowserRouter>,
);

// Helper for UI status indicator
const isMarketOpen = () => {
  const now = new Date();
  const day = now.getDay();
  const time = now.getHours() * 60 + now.getMinutes();
  return day >= 1 && day <= 5 && time >= 555 && time <= 915;
};

reportWebVitals();
