import React, { useState, useEffect, useMemo, use } from "react";
import { BrowserRouter, useParams, useSearchParams } from "react-router";
import {
  RefreshCw,
  TrendingUp,
  TrendingDown,
  Activity,
  Target,
  ShieldAlert,
  ShieldCheck,
  Zap,
} from "lucide-react";
import { fetchFromAPI } from "./services/getapi";
import OptionChain from "./OptionChain";
import OptionBuySell from "./OptionBuySell";
import Iframe from "./Iframe";
import CandleModalApp from "./CandleModalApp";
import CandleChart from "./CandleChart";

const OptionChainApp = ({ lastRefresh, isMarketOpen }) => {
  const localVal =
    window?.localStorage?.getItem("index") === "BANKNIFTY"
      ? "BANKNIFTY"
      : "NIFTY";
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [analysis, setAnalysis] = useState({});
  const [expUpdate, setExpire] = useState(window?.localStorage?.getItem("exp"));
  const [expireDates, setExpiryDates] = useState([]);
  const [dayHighlow, setDayHighlow] = useState([]);
  const [holiday, setHoliday] = useState([]);
  const [marketType, setMarketType] = useState(localVal);
  const [marketStats, setMarketStats] = useState({
    spot: 0,
    high: 0,
    low: 0,
    pcr: 0,
    totalCE_OI: 0,
    totalPE_OI: 0,
    totalCE_ChngOI: 0,
    totalPE_ChngOI: 0,
    totalCE_Vol: 0,
    totalPE_Vol: 0,
  });
  const [searchParams] = useSearchParams();
  const calculateDelta = (strike, spot, iv, isCall) => {
    if (!iv || iv === 0)
      return isCall ? (strike < spot ? 0.7 : 0.3) : strike > spot ? -0.7 : -0.3;
    const diff = Math.log(spot / strike);
    const delta = isCall
      ? 1 / (1 + Math.exp(-diff * 10))
      : -(1 / (1 + Math.exp(diff * 10)));
    return delta.toFixed(2);
  };

  const fetchexpireDate = async () => {
    setLoading(true);
    try {
      const response = fetchFromAPI(
        `NextApi/apiClient/GetQuoteApi?functionName=getOptionChainDropdown&symbol=${marketType}`,
        "GET",
        searchParams,
      );
      const json = await response;
      setExpiryDates(json?.expiryDates);
      setExpire(json?.expiryDates[0]);
    } catch (error) {
      console.error("Fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchholiday = async () => {
    setLoading(true);
    try {
      const response = fetchFromAPI(
        "holiday-master?type=trading",
        "GET",
        searchParams,
      );
      const json = await response;
      setHoliday(json);
    } catch (error) {
      console.error("Fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchDataAnalysis = async () => {
    setLoading(true);
    try {
      const response = fetchFromAPI(
        `NextApi/apiClient/indexTrackerApi?functionName=getAdvanceDecline&&index=${marketType}%2050`,
        "GET",
        searchParams,
      );
      const json = await response;
      setAnalysis(json?.data[0]);
    } catch (error) {
      console.error("Fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchDataAnalysisMarket = async () => {
    setLoading(true);
    try {
      const response = fetchFromAPI(
        "NextApi/apiClient?functionName=getIndexData&&type=All",
        "GET",
        searchParams,
      );
      const json = await response;
      setDayHighlow(json?.data[0]);
    } catch (error) {
      console.error("Fetch error:", error);
    } finally {
      setLoading(false);
    }
  };
  const fetchData = async () => {
    setLoading(true);
    try {
      const response = fetchFromAPI(
        `NextApi/apiClient/GetQuoteApi?functionName=getOptionChainData&symbol=${marketType}&params=expiryDate=${expUpdate}`,
        "GET",
        searchParams,
      );
      const json = await response;
      const spotPrice = json?.underlyingValue;
      const rawData = json.data.sort((a, b) => a.strikePrice - b.strikePrice);
      const topItems = rawData
        ?.filter((v) => v?.strikePrice > spotPrice)
        ?.sort((a, b) => a.strikePrice - b.strikePrice)
        ?.slice(0, 8);
      const bottomItems = rawData
        ?.filter((v) => v?.strikePrice < spotPrice)
        ?.sort((a, b) => b.strikePrice - a.strikePrice)
        ?.slice(0, 8)
        .sort((a, b) => a.strikePrice - b.strikePrice);
      const currentItems = [...bottomItems, ...topItems];

      setData(currentItems);

      // Aggregating Totals
      const totals = rawData.reduce(
        (acc, curr) => ({
          ceOI: acc.ceOI + (curr.CE?.openInterest || 0),
          peOI: acc.peOI + (curr.PE?.openInterest || 0),
          ceChng: acc.ceChng + (curr.CE?.changeinOpenInterest || 0),
          peChng: acc.peChng + (curr.PE?.changeinOpenInterest || 0),
          ceVol: acc.ceVol + (curr.CE?.totalTradedVolume || 0),
          peVol: acc.peVol + (curr.PE?.totalTradedVolume || 0),
        }),
        { ceOI: 0, peOI: 0, ceChng: 0, peChng: 0, ceVol: 0, peVol: 0 },
      );

      const spot = rawData[0]?.["CE"]?.underlyingValue || 0;
      setMarketStats({
        spot: spot,
        high: spot * 1.005,
        low: spot * 0.995,
        pcr: totals.ceOI > 0 ? (totals.peOI / totals.ceOI).toFixed(2) : 0,
        totalCE_OI: totals.ceOI,
        totalPE_OI: totals.peOI,
        totalCE_ChngOI: totals.ceChng,
        totalPE_ChngOI: totals.peChng,
        totalCE_Vol: totals.ceVol,
        totalPE_Vol: totals.peVol,
      });
      console.log("button clicked and last refresh", lastRefresh);
    } catch (error) {
      console.error("Fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const levels = useMemo(() => {
    if (!data.length) return { resistance: [], support: [] };
    const res = [...data]
      .sort((a, b) => (b.CE?.openInterest || 0) - (a.CE?.openInterest || 0))
      .slice(0, 5);
    const sup = [...data]
      .sort((a, b) => (b.PE?.openInterest || 0) - (a.PE?.openInterest || 0))
      .slice(0, 5);
    return {
      resistance: res
        .filter((v) => v.strikePrice > marketStats?.spot?.toFixed(2))
        .map((item) => item.strikePrice)
        .sort((a, b) => a - b),
      support: sup
        .filter((v) => v.strikePrice < marketStats?.spot?.toFixed(2))
        ?.map((item) => item.strikePrice)
        .sort((a, b) => b - a),
    };
  }, [data]);

  useEffect(() => {
    fetchexpireDate();
    fetchholiday();
    fetchDataAnalysis();
    fetchDataAnalysisMarket();
  }, []);

  useEffect(() => {
    if (expUpdate) {
      fetchData();
    }
  }, [expUpdate]);

  const updateHoliday = () => {
    const data = holiday?.["CBM"];
    // Create a "floor" date set to the first day of the current month
    const now = new Date();
    const firstOfCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1);

    const upcomingHolidays = data?.filter((item) => {
      const [day, monthStr, year] = item.tradingDate.split("-");

      // Parse the item date (e.g., "01-May-2026")
      const itemDate = new Date(`${monthStr} ${day}, ${year}`);

      // Return true only if the date is today or in the future months
      return itemDate >= firstOfCurrentMonth;
    });
    return (
      <select>
        {upcomingHolidays?.map((v) => (
          <option className="holidays" title={v?.description}>
            <span>
              {v?.tradingDate} <p>{v?.weekDay}</p>
            </span>
          </option>
        ))}
      </select>
    );
  };

  const selectExpireDate = () => {
    return (
      <select onChange={(e) => setExpire(e?.target?.value)}>
        {expireDates?.map((v) => (
          <option className="expiryDates">
            <span>{v}</span>
          </option>
        ))}
      </select>
    );
  };

  function getOptionValues(spot, strike, premium, type) {
    let intrinsicValue = 0;

    if (type.toLowerCase() === "call") {
      // Call: Profit if Spot > Strike
      intrinsicValue = Math.max(0, spot - strike);
    } else if (type.toLowerCase() === "put") {
      // Put: Profit if Strike > Spot
      intrinsicValue = Math.max(0, strike - spot);
    }

    const timeValue = premium - intrinsicValue;

    return {
      intrinsicValue: intrinsicValue.toFixed(2),
      timeValue: timeValue.toFixed(2),
    };
  }

  const devideBy = 100000;
  const handlerChanges = () => {
    let resp = window.localStorage.getItem("index");
    if (resp) {
      window.localStorage.removeItem("index");
    } else {
      window.localStorage.setItem("index", "BANKNIFTY");
    }
    window.location.reload();
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-8 font-sans text-slate-900">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
          <div>
            <h1 className="text-2xl font-black flex items-center gap-2 tracking-tight text-slate-800">
              <Activity className="text-blue-600" /> {marketType} PRO-CHAIN{" "}
              <Zap size={20} className="text-yellow-500 fill-yellow-500" />
            </h1>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">
              Expiry: {expUpdate}
              <span>
                ___Last Updated: <strong>{lastRefresh}</strong>{" "}
                {isMarketOpen() ? "🟢 Active" : "⚪ Standby"}
              </span>
            </p>
          </div>
          <div className="flex gap-2">
            <button
              onClick={() => handlerChanges()}
              className="flex items-center gap-2 bg-slate-900 hover:bg-black text-white px-6 py-2 rounded-lg font-bold transition-all shadow-lg active:scale-95"
            >
              {marketType}
            </button>
            <button
              onClick={fetchData}
              disabled={loading}
              id="refreshElement"
              className="flex items-center gap-2 bg-slate-900 hover:bg-black text-white px-6 py-2 rounded-lg font-bold transition-all shadow-lg active:scale-95"
            >
              <RefreshCw
                className={`w-4 h-4 ${loading ? "animate-spin" : ""}`}
              />
              {loading ? "SYNCING..." : "REFRESH FEED"}
            </button>
          </div>
        </div>

        {/* Market Stats */}

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
          <StatCard
            title="Spot Price"
            value={marketStats.spot.toFixed(2)}
            icon={<Target className="text-blue-500" />}
            color="border-blue-500"
          />
          <StatCard
            title="PCR (OI)"
            value={marketStats.pcr}
            icon={<Activity className="text-purple-500" />}
            color="border-purple-500"
          />
          <StatCard
            title="Session High"
            value={dayHighlow?.high}
            icon={<TrendingUp className="text-green-500" />}
            color="border-green-500"
          />
          <StatCard
            title="Session Low"
            value={dayHighlow?.low}
            icon={<TrendingDown className="text-red-500" />}
            color="border-red-500"
          />
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-6 gap-4 mb-6">
          <StatCard
            title="Advances"
            value={analysis?.advance_symbol}
            color="border-blue-100"
          />
          <StatCard
            title="Declines"
            value={analysis?.decline_symbol}
            color="border-blue-100"
          />
          <StatCard
            title="Unchanged"
            value={analysis?.unchanged_symbol}
            color="border-blue-100"
          />
          <StatCard
            title="Total"
            value={analysis?.total_symbol}
            color="border-blue-100"
          />{" "}
          <StatCard
            title="Holiday"
            value={updateHoliday()}
            color="border-blue-100"
          />
          <StatCard
            title="Select Expiry"
            value={selectExpireDate()}
            color="border-blue-100"
          />
        </div>

        {/* Option Chain Table */}
        <OptionBuySell
          data={data}
          spot={marketStats?.spot.toFixed(2)}
          lastRefresh={lastRefresh}
          isMarketOpen={isMarketOpen}
        />
        <div className="bg-white rounded-xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto max-h-[1000px]">
            <table className="w-full text-sm text-center border-collapse">
              <thead className="bg-slate-900 text-white sticky top-0 z-30 font-bold uppercase tracking-tighter text-[11px]">
                <tr>
                  <th
                    colSpan="7"
                    className="py-4 border-r border-slate-700 text-blue-400"
                  >
                    Calls
                  </th>
                  <th className="bg-blue-600 px-4">Strike</th>
                  <th
                    colSpan="8"
                    className="py-2 border-l border-slate-700 text-green-400"
                  >
                    Puts
                  </th>
                </tr>
                <tr className="bg-slate-100 text-slate-500 font-black border-b">
                  <th className="p-2 border-r">Delta</th>
                  <th className="p-2 border-r">IV</th>
                  <th className="p-2 border-r">OI</th>
                  <th className="p-2 border-r">CHG OI</th>
                  <th className="p-2 border-r">VOL</th>
                  <th className="p-2 border-r text-slate-900">
                    TIME / INT VAL
                  </th>
                  <th className="p-2 border-r text-slate-900">LTP</th>
                  <th className="p-2 bg-white text-blue-600 border-x wid-150">
                    PRICE
                  </th>
                  <th className="p-2 border-l text-slate-900">LTP</th>
                  <th className="p-2 border-r text-slate-900">
                    TIME / INT VAL
                  </th>
                  <th className="p-2 border-l">VOL</th>
                  <th className="p-2 border-l">CHNG OI</th>
                  <th className="p-2 border-l">OI</th>
                  <th className="p-2 border-l">IV</th>
                  <th className="p-2">Delta</th>
                </tr>
              </thead>
              <tbody>
                {data.map((item, idx) => {
                  const spot = marketStats.spot;
                  const isCallITM = item.strikePrice < spot;
                  const isPutITM = item.strikePrice > spot;
                  const isATM =
                    item.strikePrice >= spot &&
                    data[idx - 1]?.strikePrice < spot;
                  const CEVAL = Math.floor(spot - item.strikePrice);
                  const PEVAL = Math.floor(item.strikePrice - spot);

                  const callOption = getOptionValues(
                    spot,
                    item.strikePrice,
                    item.CE?.lastPrice,
                    "call",
                  );

                  const putOption = getOptionValues(
                    spot,
                    item.strikePrice,
                    item.PE?.lastPrice,
                    "put",
                  );

                  const CE_INTVAL = `${callOption?.timeValue}____${callOption?.intrinsicValue}`;
                  const PE_INTVAL = `${putOption?.timeValue}____${putOption?.intrinsicValue}`;
                  return (
                    <tr
                      key={item.strikePrice}
                      className={`border-b border-slate-50 transition-all hover:bg-slate-50/50 ${isATM ? "bg-yellow-50 ring-2 ring-inset ring-yellow-200" : ""}`}
                    >
                      <td className="p-2 border-r text-[10px] ">
                        {calculateDelta(
                          item.strikePrice,
                          spot,
                          item.CE?.impliedVolatility,
                          true,
                        )}
                      </td>
                      <td className="p-2 border-r text-[10px] ">
                        {item.CE?.impliedVolatility?.toFixed(1) || "-"}
                      </td>
                      <td
                        className={`p-2 border-r  ${!isATM && levels.resistance.includes(item.strikePrice) ? "text-red-600 bg-red-50 font-bold" : ""}`}
                      >
                        {item.CE?.openInterest?.toLocaleString()}
                      </td>
                      <td
                        className={`p-2 border-r text-[10px] font-bold ${item.CE?.changeinOpenInterest < 0 ? "text-red-500" : "text-green-600"}`}
                      >
                        {item.CE?.changeinOpenInterest || 0}
                      </td>
                      <td className="p-2 border-r text-[10px] text-slate-400">
                        <b style={{ color: "#5b5050" }}>
                          {Math.floor(item.CE?.totalTradedVolume / 100000)}-L
                        </b>
                      </td>
                      <td className="p-2 border-r text-[10px] ">{CE_INTVAL}</td>
                      <td className="p-2 border-r font-bold text-slate-600">
                        {item.CE?.lastPrice || 0}
                      </td>
                      <td
                        className={`p-2 font-black border-x ${isATM ? "bg-blue-600 text-white" : "bg-slate-50"}`}
                      >
                        {item.strikePrice}
                      </td>

                      <td className="p-2 border-l font-bold text-slate-600">
                        {item.PE?.lastPrice || 0}
                      </td>

                      <td className="p-2 border-r text-[10px] ">{PE_INTVAL}</td>
                      <td className="p-2 border-l text-[10px] text-slate-400">
                        <b style={{ color: "#5b5050" }}>
                          {Math.floor(item.PE?.totalTradedVolume / 100000)}-L
                        </b>
                      </td>
                      <td
                        className={`p-2 border-l text-[10px] font-bold ${item.PE?.changeinOpenInterest < 0 ? "text-red-500" : "text-green-600"}`}
                      >
                        {item.PE?.changeinOpenInterest || 0}
                      </td>
                      <td
                        className={`p-2 border-l ${levels.support.includes(item.strikePrice) ? "text-green-600 bg-green-50  font-bold" : ""}`}
                      >
                        {item.PE?.openInterest?.toLocaleString()}
                      </td>
                      <td className="p-2 border-l text-[10px]">
                        {item.PE?.impliedVolatility?.toFixed(1) || "-"}
                      </td>
                      <td className="p-2 border-r text-[10px] ">
                        {calculateDelta(
                          item.strikePrice,
                          spot,
                          item.PE?.impliedVolatility,
                          false,
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              {/* Total Aggregates Footer */}
              <tfoot className="bg-slate-800 text-white font-black text-[11px] sticky bottom-0 z-30 uppercase">
                <tr>
                  <td
                    colSpan="2"
                    className="p-3 text-right text-slate-400 border-r border-slate-700"
                  >
                    TOTALS
                  </td>
                  <td className="p-3 border-r text-blue-300 f-20">
                    {marketStats.totalCE_OI.toLocaleString()}
                  </td>
                  <td className="p-3 border-r text-blue-300">
                    {marketStats.totalCE_ChngOI.toLocaleString()}
                  </td>
                  <td className="p-3 border-r text-blue-300 f-20">
                    {marketStats.totalCE_Vol.toLocaleString()}
                  </td>
                  <td className="p-3 border-r"></td>
                  <td className="bg-slate-900 border-x border-slate-700"></td>
                  <td className="p-3 border-l"></td>
                  <td className="p-3 border-l"></td>
                  <td className="p-3 border-l"></td>
                  <td className="p-3 border-l text-green-300 f-20">
                    {marketStats.totalPE_Vol.toLocaleString()}
                  </td>
                  <td className="p-3 border-l text-green-300">
                    {marketStats.totalPE_ChngOI.toLocaleString()}
                  </td>
                  <td className="p-3 border-l text-green-300 f-20">
                    {marketStats.totalPE_OI.toLocaleString()}
                  </td>
                  <td colSpan="2" className="p-3"></td>
                </tr>
                <tr style={{ background: "#494e61" }}>
                  <td
                    colSpan="2"
                    className="p-3 text-right text-slate-400 border-r border-slate-700"
                  >
                    TOTALS DevideBy ({devideBy})
                  </td>
                  <td className="p-3 border-r text-blue-300 f-20">
                    {Math.floor(marketStats.totalCE_OI / devideBy)} L
                  </td>
                  <td className="p-3 border-r text-blue-300">
                    {Math.floor(marketStats.totalCE_ChngOI / devideBy)} L
                  </td>
                  <td className="p-3 border-r text-blue-300 f-20">
                    {Math.floor(marketStats.totalCE_Vol / devideBy)} L
                  </td>
                  <td className="p-3 border-r"></td>
                  <td className="bg-slate-900 border-x border-slate-700"></td>
                  <td className="p-3 border-l"></td>
                  <td className="p-3 border-l"></td>
                  <td className="p-3 border-l"></td>
                  <td className="p-3 border-l text-green-300 f-20">
                    {Math.floor(marketStats.totalPE_Vol / devideBy)} L
                  </td>
                  <td className="p-3 border-l text-green-300">
                    {Math.floor(marketStats.totalPE_ChngOI / devideBy)} L
                  </td>
                  <td className="p-3 border-l text-green-300 f-20">
                    {Math.floor(marketStats.totalPE_OI / devideBy)} L
                  </td>
                  <td colSpan="2" className="p-3"></td>
                </tr>
              </tfoot>
            </table>
          </div>
        </div>
        <br></br>

        <OptionChain
          expUpdate={expUpdate}
          spot={marketStats?.spot.toFixed(2)}
          lastRefresh={lastRefresh}
          isMarketOpen={isMarketOpen}
          Type={marketType}
        />
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color }) => (
  <div className={`bg-white p-4 rounded-xl border-t-4 ${color} shadow-lg`}>
    <div className="flex items-center justify-between mb-1">
      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
        {title}
      </span>
      {icon}
    </div>
    <div className="text-xl font-black text-slate-900">{value}</div>
  </div>
);

const styles = {
  card: {
    padding: "20px",
    border: "1px solid #ddd",
    borderRadius: "12px",
    maxWidth: "400px",
    margin: "40px auto",
    textAlign: "center",
    boxShadow: "0 4px 6px rgba(0,0,0,0.1)",
    fontFamily: "Segoe UI, Tahoma, Geneva, Verdana, sans-serif",
  },
  status: { color: "#444", lineHeight: "1.6" },
};

export default OptionChainApp;
