import axios from "axios";

export const fetchFromAPI = async (endpoint, method, searchParam) => {
  try {
    const data = searchParam.get("data");
    console.log(data);
    const urlParam = `https://www.nseindia.com/api/${endpoint}`;
    const url =
      data !== "online"
        ? urlParam
        : "https://badayaservissss-g9aabae4eubqdbdp.canadacentral-01.azurewebsites.net/service/mydata";
    let head = {
      apiext: urlParam,
      apitype: "newapi",
      "Content-Type": "application/json",
    };
    const myHeaders =
      data === "online"
        ? { ...head }
        : {
            "Content-Type": "application/json",
          };
    let response;
    response = await axios({
      url,
      headers: myHeaders,
      method,
    });
    return response.data;
  } catch (error) {
    console.error("API Fetch Error:", error);
    throw error;
  }
};
