import React, { useState } from "react";

// 1. Single Candlestick Component built using Props
const SingleCandle = ({ open, high, low, close, height = 200, candleData }) => {
  const isBullish = close >= open;
  const candleColor = isBullish ? "#089981" : "#f23645"; // Standard trading colors

  // Establish bounds to map prices to percentages
  const maxPrice = high;
  const minPrice = low;
  const priceRange = maxPrice - minPrice === 0 ? 1 : maxPrice - minPrice;

  // Calculate relative top percentage offsets for every unique point (0% top, 100% bottom)
  const highTop = 0;
  const lowTop = 100;
  const openTop = ((maxPrice - open) / priceRange) * 100;
  const closeTop = ((maxPrice - close) / priceRange) * 100;

  // Geometric body positioning limits
  const bodyTop = ((maxPrice - Math.max(open, close)) / priceRange) * 100;
  const bodyBottom = ((maxPrice - Math.min(open, close)) / priceRange) * 100;
  const bodyHeight = Math.max(bodyBottom - bodyTop, 1); // Ensure at least 1% visibility

  // Reusable label element builder function
  const renderLabel = (text, value, topPercent, side = "left") => (
    <div
      style={{
        position: "absolute",
        top: `${topPercent}%`,
        [side]: "-65px", // Push label outside the candle body width limits
        transform: "translateY(-50%)",
        fontSize: "10px",
        fontWeight: "bold",
        color: "#1e293b",
        backgroundColor: "#f8fafc",
        padding: "2px 4px",
        borderRadius: "4px",
        border: `1px solid ${candleColor}`,
        whiteSpace: "nowrap",
        zIndex: 2,
        pointerEvents: "none",
      }}
    >
      {text}: {value}
    </div>
  );

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        fontFamily: "sans-serif",
      }}
    >
      {/* Interactive visual metrics container with lateral margin safety paddings */}
      <div
        style={{
          position: "relative",
          width: "60px",
          height: `${height}px`,
          margin: "20px 70px", // Added margins to make room for absolute labels
        }}
      >
        {/* Absolute Coordinate Visual Markings */}
        {renderLabel("H", high, highTop, "left")}
        {renderLabel("O", open, openTop, isBullish ? "left" : "right")}
        {renderLabel("C", close, closeTop, isBullish ? "right" : "left")}
        {renderLabel("L", low, lowTop, "left")}

        {/* Wick (High to Low Line) */}
        <div
          style={{
            position: "absolute",
            left: "50%",
            top: `${highTop}%`,
            bottom: `${100 - lowTop}%`,
            width: "2px",
            backgroundColor: candleColor,
            transform: "translateX(-50%)",
          }}
        />

        {/* Real Body (Open to Close Box) */}
        <div
          style={{
            position: "absolute",
            left: "0",
            top: `${bodyTop}%`,
            width: "100%",
            height: `${bodyHeight}%`,
            backgroundColor: candleColor,
            borderRadius: "2px",
            transition: "all 0.3s ease",
          }}
        />
      </div>

      {/* Metrics Data Grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "8px",
          fontSize: "14px",
          width: "100%",
          marginTop: "10px",
        }}
      >
        <div>
          <strong>High:</strong> {high}
        </div>
        <div>
          <strong>Open:</strong> {open}
        </div>
        <div>
          <strong>Close:</strong> {close}
        </div>
        <div>
          <strong>Low:</strong> {low}
        </div>
        <div>
          <strong>Volume:</strong>{" "}
          {candleData?.totalTradedVolume
            ? `${Math.floor(candleData.totalTradedVolume / 100000)} L`
            : "0 L"}
        </div>
        <div>
          <strong>pre Close:</strong> {candleData?.prevClose || "N/A"}
        </div>
      </div>
    </div>
  );
};

// 2. Popup Modal Component
const Modal = ({ isOpen, onClose, candleData }) => {
  if (!isOpen) return null; // Conditional rendering

  return (
    <div
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        width: "100vw",
        height: "100vh",
        backgroundColor: "rgba(0, 0, 0, 0.5)", // Backdrop shadow
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        zIndex: 1000,
      }}
      onClick={onClose}
    >
      <div
        style={{
          backgroundColor: "#fff",
          padding: "24px",
          borderRadius: "8px",
          width: "340px", // Expanded slightly to guarantee spatial marking layout containment
          boxShadow: "0 4px 15px rgba(0,0,0,0.2)",
          position: "relative",
        }}
        onClick={(e) => e.stopPropagation()}
      >
        <h3 style={{ margin: "0 0 16px 0", textAlign: "center" }}>
          Asset Analytics
        </h3>
        {/* Injecting data into our Candle layout */}
        <SingleCandle
          open={candleData.open}
          high={candleData.high}
          low={candleData.low}
          close={candleData.close}
          candleData={candleData}
        />
        <br></br>
        <b>{candleData?.strikePrice}</b>
        <button
          onClick={onClose}
          style={{
            marginTop: "20px",
            width: "100%",
            padding: "10px",
            backgroundColor: "#161b26",
            color: "#fff",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer",
          }}
        >
          Close Preview
        </button>
      </div>
    </div>
  );
};

// 3. Parent App Template Component
export default function CandleModalApp({
  isModalOpen,
  setIsModalOpen,
  propData,
}) {
  const sampleCandleProps = {
    open: propData?.openPrice,
    high: propData?.highPrice,
    low: propData?.lowPrice,
    close: propData?.closePrice ? propData?.closePrice : propData?.lastPrice,
    ...propData,
  };

  return (
    <div
      style={{ padding: "40px", textAlign: "center", fontFamily: "sans-serif" }}
    >
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        candleData={sampleCandleProps}
      />
    </div>
  );
}
