import React, { useState, useEffect } from "react";
import ReactApexChart from "react-apexcharts";

// Your custom JSON options data object wrapped in an array sample
const optionsDataSample = [
  {
    change: 22.65,
    changeinOpenInterest: -1065,
    closePrice: 0,
    expiryDate: "23-Jun-2026",
    highPrice: 162,
    identifier: "OPTIDXNIFTY23-06-2026PE24000.00",
    instrumentType: "OPTIDX",
    lastPrice: 72.35, // Used as Close Price since closePrice is 0
    lowPrice: 68.75,
    openInterest: 148292,
    openPrice: 112.1,
    optionType: "PE",
    pchange: 45.57344064386318,
    pchangeinOpenInterest: -0.7130566361134731,
    prevClose: 49.7,
    strikePrice: "   24000.00",
    ticksize: 0.05,
    totalTradedVolume: 6190307,
    totalTurnover: 49487480765.45,
    underlying: "NIFTY",
    underlyingValue: 24013.1,
    volumeFreezeQuantity: 1801,
    time: "2026-06-19T09:30:00",
  },
];

const CandleChart = () => {
  const [chartData, setChartData] = useState([]);
  const [annotations, setAnnotations] = useState({ points: [] });

  useEffect(() => {
    const pointAnnotations = [];

    const formattedData = optionsDataSample.map((item) => {
      const timestamp = new Date(item.time).getTime();

      // Determine real Close Price from lastPrice if closePrice arrives as 0
      const cleanClosePrice =
        item.closePrice === 0 ? item.lastPrice : item.closePrice;

      // Extract details for the on-candle text layout badge
      pointAnnotations.push({
        x: timestamp,
        y: item.highPrice,
        marker: {
          size: 5,
          fillColor: "#008ffb",
          strokeColor: "#fff",
        },
        label: {
          borderColor: "#008ffb",
          style: {
            color: "#fff",
            background: "#008ffb",
            fontSize: "11px",
          },
          offsetY: -10,
          // Shows target option identifier parameters directly across the graph grid space
          text: `${item.underlying} ${item.expiryDate} Strike: ${item.strikePrice.trim()} ${item.optionType}`,
        },
      });

      return {
        x: timestamp,
        y: [item.openPrice, item.highPrice, item.lowPrice, cleanClosePrice],
        // Save additional custom metadata fields for our tooltip handler below
        volume: item.totalTradedVolume,
        oi: item.openInterest,
        oiChange: item.changeinOpenInterest,
        pchange: item.pchange,
        underlyingValue: item.underlyingValue,
      };
    });

    setChartData(formattedData);
    setAnnotations({ points: pointAnnotations });
  }, []);

  const options = {
    chart: {
      type: "candlestick",
      height: 380,
      toolbar: { show: true },
    },
    title: {
      text: "NIFTY Derivatives Options Analytics Tracker",
      align: "left",
    },
    annotations: annotations,
    xaxis: {
      type: "datetime",
      labels: {
        datetimeUTC: false,
        format: "HH:mm",
      },
    },
    yaxis: {
      title: { text: "Premium Price" },
      tooltip: { enabled: true },
    },
    tooltip: {
      custom: function ({ seriesIndex, dataPointIndex, w }) {
        const item = w.config.series[seriesIndex].data[dataPointIndex];
        if (!item) return "";

        const [open, high, low, close] = item.y;
        const oiColor = item.oiChange >= 0 ? "#26a69a" : "#ef5350";
        const priceColor = item.pchange >= 0 ? "#26a69a" : "#ef5350";

        return `
          <div style="padding: 14px; background: #1a1a1a; color: #fff; border-radius: 6px; font-family: Roboto, sans-serif; font-size: 12px; min-width: 230px; line-height: 1.7; box-shadow: 0 4px 15px rgba(0,0,0,0.5);">
            <div style="font-weight: bold; color: #ffb300; margin-bottom: 6px; border-bottom: 1px solid #333; padding-bottom: 4px;">
              Spot Price: ${item.underlyingValue}
            </div>
            <div><span style="color: #888;">Open (Premium):</span> <b style="float: right;">${open.toFixed(2)}</b></div>
            <div><span style="color: #888;">High (Premium):</span> <b style="float: right;">${high.toFixed(2)}</b></div>
            <div><span style="color: #888;">Low (Premium):</span> <b style="float: right;">${low.toFixed(2)}</b></div>
            <div><span style="color: #888;">LTP (Close):</span> <b style="float: right;">${close.toFixed(2)}</b></div>
            
            <div style="margin-top: 4px; border-top: 1px solid #333; padding-top: 4px;">
              <span style="color: #888;">Price Change %:</span> 
              <b style="float: right; color: ${priceColor};">${item.pchange.toFixed(2)}%</b>
            </div>
            <div>
              <span style="color: #888;">Open Interest (OI):</span> 
              <b style="float: right;">${item.oi.toLocaleString()}</b>
            </div>
            <div>
              <span style="color: #888;">OI Change:</span> 
              <b style="float: right; color: ${oiColor};">${item.oiChange.toLocaleString()}</b>
            </div>
            <div style="color: #008ffb; font-weight: bold;">
              <span>Volume:</span> 
              <span style="float: right;">${item.volume.toLocaleString()}</span>
            </div>
          </div>
        `;
      },
    },
    plotOptions: {
      candlestick: {
        colors: {
          upward: "#26a69a",
          downward: "#ef5350",
        },
      },
    },
  };

  const series = [{ data: chartData }];

  return (
    <div
      style={{ backgroundColor: "#fff", padding: "20px", borderRadius: "8px" }}
    >
      <ReactApexChart
        options={options}
        series={series}
        type="candlestick"
        height={380}
      />
    </div>
  );
};

export default CandleChart;
