import React, { useState, useEffect, useMemo } from "react";
import {
  RefreshCw,
  TrendingUp,
  TrendingDown,
  Activity,
  Target,
  ShieldAlert,
  ShieldCheck,
  Zap,
} from "lucide-react";
import { fetchFromAPI } from "./services/getapi";
import { BrowserRouter, useParams, useSearchParams } from "react-router";
import Iframe from "./Iframe";
import CandleModalApp from "./CandleModalApp";

const OptionChain = ({ expUpdate, spot, lastRefresh, isMarketOpen, Type }) => {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [propData, setPropData] = useState(null);
  const [searchParams] = useSearchParams();

  const calculateDelta = (strike, spot, iv, isCall) => {
    if (!iv || iv === 0)
      return isCall ? (strike < spot ? 0.7 : 0.3) : strike > spot ? -0.7 : -0.3;
    const diff = Math.log(spot / strike);
    const delta = isCall
      ? 1 / (1 + Math.exp(-diff * 10))
      : -(1 / (1 + Math.exp(diff * 10)));
    return delta.toFixed(2);
  };

  const fetchData = async () => {
    setLoading(true);
    try {
      const response = fetchFromAPI(
        `NextApi/apiClient/GetQuoteApi?functionName=getSymbolDerivativesData&symbol=${Type}&expiryDt=${expUpdate}`,
        "GET",
        searchParams,
      );
      const json = await response;
      const spotPrice = json?.data?.[0]?.underlyingValue;
      const rawData = json?.data?.sort((a, b) => a.strikePrice - b.strikePrice);
      const topItems = rawData
        ?.filter((v) => v?.strikePrice > spotPrice)
        ?.sort((a, b) => a.strikePrice - b.strikePrice)
        ?.slice(0, 15);
      const bottomItems = rawData
        ?.filter((v) => v?.strikePrice < spotPrice)
        ?.sort((a, b) => b.strikePrice - a.strikePrice)
        ?.slice(0, 15)
        .sort((a, b) => a.strikePrice - b.strikePrice);
      const currentItems = [...bottomItems, ...topItems];

      const formattedData = Object.values(
        currentItems?.reduce((acc, item) => {
          // Clean the strike price (remove whitespace and convert to number)
          const strike = parseFloat(item.strikePrice.trim());
          // Initialize the object for this strike price if it doesn't exist
          if (!acc[strike]) {
            acc[strike] = { strikePrice: strike };
          }
          // Assign the current item to either CE or PE key
          acc[strike][item.optionType] = item;
          return acc;
        }, {}),
      );

      setData(formattedData);

      const spot = rawData[0]?.["CE"]?.underlyingValue || 0;
    } catch (error) {
      console.error("Fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (expUpdate) {
      if (lastRefresh && isMarketOpen) {
        fetchData();
      } else {
        fetchData();
      }
    }
  }, [expUpdate, lastRefresh]);

  lastRefresh = { lastRefresh };
  isMarketOpen = { isMarketOpen };

  const devideBy = 100000;

  const handlerUpdate = (value) => {
    setIsModalOpen(true);
    setPropData(value);
    console.log(value);
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-0 font-sans text-slate-900">
      <div className="max-w-7xl mx-auto flex">
        {/* Option Chain Table */}
        {propData && isModalOpen && (
          <CandleModalApp
            isModalOpen={isModalOpen}
            setIsModalOpen={setIsModalOpen}
            propData={propData}
          />
        )}

        <div
          style={{ width: "50%" }}
          className="bg-white rounded-xl shadow-2xl border border-slate-200 overflow-hidden"
        >
          <div className="overflow-x-auto max-h-[1000px]">
            <table className="w-full text-sm text-center border-collapse">
              <thead className="bg-slate-900 text-white sticky top-0 z-30 font-bold uppercase tracking-tighter text-[11px]">
                <tr>
                  <th
                    colSpan="3"
                    className="py-4 border-r border-slate-700 text-blue-400"
                  >
                    Calls
                  </th>
                  <th className="bg-blue-600 px-4">Strike</th>
                  <th
                    colSpan="8"
                    className="py-2 border-l border-slate-700 text-green-400"
                  >
                    Puts
                  </th>
                </tr>
                <tr className="bg-slate-100 text-slate-500 font-black border-b">
                  <th className="p-2 border-r text-slate-900">View</th>
                  <th className="p-2 border-r text-slate-900">P Close</th>
                  <th className="p-2 border-r text-slate-900">Volume</th>

                  <th className="p-2 bg-white text-blue-600 border-x wid-150">
                    PRICE
                  </th>

                  <th className="p-2 border-r text-slate-900">Volume</th>
                  <th className="p-2 border-r text-slate-900">P Close</th>
                  <th className="p-2 border-r text-slate-900">View</th>
                </tr>
              </thead>
              <tbody>
                {data.map((item, idx) => {
                  const isATM =
                    item.strikePrice >= spot &&
                    data[idx - 1]?.strikePrice < spot;

                  return (
                    <tr
                      key={item.strikePrice}
                      className={`border-b border-slate-50 transition-all hover:bg-slate-50/50 ${isATM ? "bg-yellow-50 ring-2 ring-inset ring-yellow-200" : ""}`}
                    >
                      <td className="p-2 border-r font-bold text-slate-600">
                        <button onClick={() => handlerUpdate(item?.CE)}>
                          View
                        </button>
                      </td>
                      <td className="p-2 border-r font-bold text-slate-600">
                        {item?.CE?.prevClose}
                      </td>
                      <td className="p-2 border-r font-bold text-slate-600">
                        {Math.floor(item?.CE?.totalTradedVolume / 100000)} L
                      </td>

                      <td
                        className={`p-2 font-black border-x ${isATM ? "bg-blue-600 text-white" : "bg-slate-50"}`}
                      >
                        {item.strikePrice}
                      </td>

                      <td className="p-2 border-r font-bold text-slate-600">
                        {Math.floor(item?.PE?.totalTradedVolume / 100000)} L
                      </td>
                      <td className="p-2 border-r font-bold text-slate-600">
                        {item?.PE?.prevClose}
                      </td>
                      <td className="p-2 border-r font-bold text-slate-600">
                        <button onClick={() => handlerUpdate(item?.PE)}>
                          View
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        <br></br>
        <div className="max-w-7xl p-5" style={{ width: "50%" }}>
          <Iframe />
        </div>
      </div>
    </div>
  );
};

export default OptionChain;
