import React, { useState, useMemo } from "react";
import { ChevronDown, ChevronUp, BarChart2 } from "lucide-react";

const OptionBuySell = ({ data, spot }) => {
  const [isOpen, setIsOpen] = useState(false);

  const convertPrices = (num) => {
    if (!num) return "0k";
    const numStr = Math.abs(num).toString();
    if (numStr.length > 5) {
      return (num / 100000).toFixed(0) + " L";
    } else {
      return (num / 1000).toFixed(0) + "k";
    }
  };

  const totals = useMemo(() => {
    return data?.reduce(
      (acc, item) => {
        acc.ceBuy += item?.CE?.totalBuyQuantity || 0;
        acc.ceSell += item?.CE?.totalSellQuantity || 0;
        acc.peBuy += item?.PE?.totalBuyQuantity || 0;
        acc.peSell += item?.PE?.totalSellQuantity || 0;
        return acc;
      },
      { ceBuy: 0, ceSell: 0, peBuy: 0, peSell: 0 },
    );
  }, [data]);

  return (
    <div className="max-w-7xl mx-auto p-0 mb-5">
      <div className="bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden">
        {/* Accordion Header */}
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="w-full flex items-center justify-between p-4 bg-slate-900 text-white hover:bg-slate-800 transition-colors"
        >
          <div className="flex items-center gap-3">
            <BarChart2 className="text-blue-400" size={20} />
            <span className="font-bold tracking-wide">
              TOTAL OPTION BUY/SELL DATA
            </span>
            <div className="hidden md:flex gap-4 ml-6 text-[10px] uppercase opacity-80">
              <span className="text-blue-400 font-bold">
                CE Buy:<b className="f-25"> {convertPrices(totals.ceBuy)}</b>
              </span>
              <span className="text-blue-400 font-bold">
                CE Sell: <b className="f-25">{convertPrices(totals.ceSell)}</b>
              </span>
            </div>

            <div className="hidden md:flex gap-4 ml-6 text-[10px] uppercase opacity-80">
              <span className="text-green-400 font-bold">
                PE Buy: <b className="f-25">{convertPrices(totals.peBuy)}</b>
              </span>
              <span className="text-green-400 font-bold">
                PE Sell: <b className="f-25">{convertPrices(totals.peSell)}</b>
              </span>
            </div>
          </div>
          {isOpen ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
        </button>

        {/* Accordion Content */}
        {isOpen && (
          <div className="overflow-x-auto max-h-[600px] animate-in fade-in slide-in-from-top-1">
            <table className="w-full text-sm text-center border-collapse">
              <thead className="bg-slate-100 text-slate-500 font-black border-b sticky top-0 z-20">
                <tr className="text-[11px] uppercase">
                  <th className="p-2 border-r text-blue-600">CE Total Buy</th>
                  <th className="p-2 border-r text-blue-600">CE Total Sell</th>
                  <th className="p-2 bg-white text-slate-900 border-x">
                    Strike
                  </th>
                  <th className="p-2 border-r text-green-600">PE Total Buy</th>
                  <th className="p-2 border-r text-green-600">PE Total Sell</th>
                </tr>
              </thead>

              <tbody>
                {data?.map((item, idx) => {
                  const isATM =
                    item.strikePrice >= spot &&
                    data[idx - 1]?.strikePrice < spot;
                  return (
                    <tr
                      key={item.strikePrice}
                      className={`border-b hover:bg-slate-50 ${isATM ? "bg-yellow-50" : ""}`}
                    >
                      <td className="p-2 border-r font-medium">
                        {convertPrices(item?.CE?.totalBuyQuantity)}
                      </td>
                      <td className="p-2 border-r font-medium text-slate-400">
                        {convertPrices(item?.CE?.totalSellQuantity)}
                      </td>
                      <td
                        className={`p-2 font-bold border-x ${isATM ? "bg-blue-600 text-white" : "bg-slate-50"}`}
                      >
                        {item.strikePrice}
                      </td>
                      <td className="p-2 border-r font-medium">
                        {convertPrices(item?.PE?.totalBuyQuantity)}
                      </td>
                      <td className="p-2 border-r font-medium text-slate-400">
                        {convertPrices(item?.PE?.totalSellQuantity)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>

              <tfoot className="bg-slate-100 text-slate-900 font-black sticky bottom-0 z-20 border-t-2 border-slate-300">
                <tr>
                  <td className="p-3 border-r text-blue-600">
                    {convertPrices(totals.ceBuy)}
                  </td>
                  <td className="p-3 border-r text-blue-400">
                    {convertPrices(totals.ceSell)}
                  </td>
                  <td className="p-3 bg-white">TOTAL</td>
                  <td className="p-3 border-r text-green-600">
                    {convertPrices(totals.peBuy)}
                  </td>
                  <td className="p-3 border-r text-green-400">
                    {convertPrices(totals.peSell)}
                  </td>
                </tr>
              </tfoot>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default OptionBuySell;
